import Navbar from "@/components/ui/"
import Link from "next/link"

export default function Home() {
  return (
    <div>

      {/* Navbar */}
      <Navbar />

      {/* Hero Section */}
      <section className="text-center py-20 bg-gray-100">
        <h1 className="text-5xl font-bold text-blue-600">
          Camp Management System
        </h1>

        <p className="mt-4 text-gray-600 text-lg">
          Manage medical camps and patient records digitally.
        </p>

        <div className="mt-6">
          <Link
            href="/login"
            className="bg-blue-600 text-white px-6 py-3 rounded-lg"
          >
            Get Started
          </Link>
        </div>
      </section>

      {/* Features */}
      <section className="py-20 text-center">
        <h2 className="text-3xl font-bold">Features</h2>

        <div className="grid md:grid-cols-3 gap-10 mt-10 px-10">

          <div className="p-6 shadow rounded-lg">
            <h3 className="text-xl font-semibold">Patient Records</h3>
            <p className="text-gray-500 mt-2">
              Store and manage patient data digitally.
            </p>
          </div>

          <div className="p-6 shadow rounded-lg">
            <h3 className="text-xl font-semibold">Camp Management</h3>
            <p className="text-gray-500 mt-2">
              Organize camps and manage records easily.
            </p>
          </div>

          <div className="p-6 shadow rounded-lg">
            <h3 className="text-xl font-semibold">Reports</h3>
            <p className="text-gray-500 mt-2">
              Generate reports quickly for NGOs.
            </p>
          </div>

        </div>
      </section>

    </div>
  )
}